script:
export const meta = {
  name: 'pass4-confirm',
  description: 'Pass-4: 2-agent confirmation that each fix is appropriate AND complete',
  phases: [{ title: 'Confirm', detail: '2 confirmers per fix' }, { title: 'Tally', detail: 'collect verdicts' }],
}
const ROOT = '/Users/[REDACTED]/hc-assay'
const FIXES = [{"id": "G-001", "file": "src/assay_engine/methodology/confirm.py", "what": "_resolve_direction refuses a directionless LOCKED whole-corpus hypothesis (tail must be pre-registered; confirm-time direction is cross-check only) \u2014 closes the HARKing hole.", "test": "test_whole_corpus_rejects_directionless_locked_hypothesis"}, {"id": "G-005", "file": "src/assay_engine/methodology/confirm.py", "what": "contradiction stability asymmetry documented as intentional + opposite-tail contradiction_stability recorded in evidence.", "test": "test_whole_corpus_records_contradiction_stability_in_evidence"}, {"id": "G-006", "file": "src/assay_engine/methodology/confirm.py", "what": "confirm primitives warn when authority=None (presence-only pre-registration gate).", "test": "test_confirm_primitive_warns_on_presence_only_gate"}, {"id": "G-011", "file": "src/assay_engine/methodology/discovery.py", "what": "discover_and_confirm type-guards the confirmer return (non-Verdict -> FirewallViolation).", "test": "test_discover_and_confirm_rejects_non_verdict_confirmer"}, {"id": "G-017", "file": "src/assay_engine/methodology/confirm.py", "what": "documented that unit-level verdict is governed by the caller flag, not the locked direction (advisory).", "test": "test_unit_level_verdict_is_governed_by_caller_flag_not_locked_direction"}, {"id": "G-002", "file": "src/assay_engine/persistence/checkpoint.py", "what": "RESET lock_timeout on the bootstrap connection before it returns to the pool (session GUC leak).", "test": "test_migration_lock_timeout_is_reset_on_the_bootstrap_connection"}, {"id": "G-003", "file": "src/assay_engine/reasoning/seam.py", "what": "BULK inner bound made total via explicit httpx.Timeout(read=BULK_TIMEOUT, connect<=10) so connect+read can't exceed the outer headroom and leak the slot.", "test": "test_bulk_complete_sets_a_total_bounded_http_timeout"}, {"id": "G-004", "file": "src/assay_engine/_frozen.py", "what": "unfreeze() frozenset fallback for unorderable types sorts by stable (type name, repr) key (was hash-seed dependent).", "test": "test_unfreeze_frozenset_of_unorderable_types_is_deterministic"}, {"id": "G-009", "file": "src/assay_engine/pipeline.py", "what": "run_study persists the provenance trail as a JSON artifact and correlates it to the MLflow run (tracker.log_artifact).", "test": "test_tracker_receives_run_and_metrics_and_failures_dont_abort (asserts _provenance.json artifact)"}, {"id": "G-010", "file": "src/assay_engine/methodology/confirm.py", "what": "numpy resample-stability uses searchsorted on a sorted null (O(R) memory) instead of an R\u00d7N boolean matrix; counts identical.", "test": "test_resample_stability_numpy_path_matches_pure_python"}, {"id": "G-012", "file": "src/assay_engine/provenance.py", "what": "from_records raises typed ProvenanceError (not raw KeyError) on a record missing a required field.", "test": "test_from_records_raises_typed_error_on_malformed_record"}, {"id": "G-023", "file": "src/assay_engine/pipeline.py", "what": "corpus unit-id set computed once and reused for split-id + feature-id validation (was built twice).", "test": "(refactor; covered by existing pipeline split/feature validation tests)"}, {"id": "G-015", "file": ".github/workflows/ci.yml", "what": "SBOM step applies the same .pip-audit-ignore allowlist so an accepted advisory doesn't fail SBOM generation.", "test": "test_sbom_step_applies_the_allowlist"}, {"id": "G-016", "file": ".github/dependabot.yml + scripts/regenerate_lockfiles.sh", "what": "documented + scripted the lockfile regen Dependabot can't do (an auto-commit workflow was rejected for token/security reasons).", "test": "test_dependabot_lockfile_regen_is_documented"}, {"id": "G-022", "file": ".github/workflows/ci.yml", "what": "pip-audit==2.10.1 and pip-licenses==5.5.5 version-pinned for reproducible supply-chain gates.", "test": "test_audit_tooling_is_version_pinned"}, {"id": "G-007", "file": "scripts/capture_transcripts.py", "what": "transcript scrubber redacts the bare operator username everywhere (derived from home dir), not only in /Users|/home paths.", "test": "test_transcript_scrub_redacts_bare_operator_username"}, {"id": "G-018", "file": "src/assay_engine/reasoning/seam.py", "what": "egress denylist scrubs the entire ANTHROPIC_* namespace + NODE_EXTRA_CA_CERTS/NODE_TLS_REJECT_UNAUTHORIZED.", "test": "test_is_unsafe_subprocess_var (new params)"}, {"id": "G-019", "file": "src/assay_engine/orchestration/gates.py", "what": "Gate.evaluate type-guards the precondition return (non-GateDecision -> typed GateError).", "test": "test_gate_rejects_non_gatedecision_precondition"}, {"id": "G-020", "file": "src/assay_engine/orchestration/gatenode.py", "what": "make_gate_node raises a clear GateError on recorder failure instead of returning the update (no graph-state/trail divergence).", "test": "test_gate_node_recorder_failure_raises_not_silently_diverges"}, {"id": "G-021", "file": "src/assay_engine/baseline/determinism.py", "what": "build_baseline_artifact names the offending extra_input key when not canonicalizable.", "test": "test_build_artifact_names_the_bad_extra_input"}, {"id": "G-024", "file": "src/assay_engine/baseline/primitives.py", "what": "corrected docstring: determinism freeze copies array bytes O(size), not zero-copy/O(1).", "test": "(doc-accuracy)"}, {"id": "G-013", "file": "tests/test_baseline.py", "what": "test-discrimination: cosine fast-path test now asserts numpy dispatch + numpy==pure agreement.", "test": "test_cosine_matrix_uses_numpy_fast_path_and_agrees_with_pure"}, {"id": "G-014", "file": "tests/test_observability.py", "what": "test-discrimination: SIGTERM flush handler asserted unconditionally on the main thread.", "test": "test_install_flush_on_exit_wires_atexit_and_sigterm"}]
const VERDICT_SCHEMA = {
  type: 'object',
  required: ['fix_id', 'appropriate', 'complete', 'verdict', 'reasoning'],
  properties: {
    fix_id: { type: 'string' }, appropriate: { type: 'boolean' }, complete: { type: 'boolean' },
    verdict: { type: 'string', enum: ['CONFIRMED', 'CONCERN'] }, reasoning: { type: 'string' },
  },
}
const prompt = (f, n) =>
  `You are confirmer #${n}, independent. Confirm a production-hardening fix is BOTH appropriate (correct, no regression, idiomatic) AND complete (fully closes it; for a code change the named regression test must DISCRIMINATE — fail if the fix were reverted). Repo: ${ROOT}\nFix ${f.id} in ${f.file}\nWhat: ${f.what}\nTest(s): ${f.test}\nSteps: read the actual changed file(s); read the test and judge whether it discriminates; check no regression. For a doc/refactor item, judge correctness/coverage rather than revert-discrimination. Verdict CONFIRMED (both true) or CONCERN (something missing/wrong/under-tested). Be skeptical and specific.`
phase('Confirm')
const results = await pipeline(
  FIXES,
  f => parallel([
    () => agent(prompt(f, 1), { label: 'cA:' + f.id, phase: 'Confirm', schema: VERDICT_SCHEMA }),
    () => agent(prompt(f, 2), { label: 'cB:' + f.id, phase: 'Confirm', schema: VERDICT_SCHEMA }),
  ]),
  (vs, f) => {
    const [a, b] = vs.filter(Boolean)
    const both = a && b && a.verdict === 'CONFIRMED' && b.verdict === 'CONFIRMED'
    return { fix_id: f.id, both_confirmed: both,
      a: a ? { v: a.verdict, ap: a.appropriate, co: a.complete, why: a.reasoning } : null,
      b: b ? { v: b.verdict, ap: b.appropriate, co: b.complete, why: b.reasoning } : null }
  }
)
phase('Tally')
const confirmed = results.filter(Boolean).filter(r => r.both_confirmed)
const concerns = results.filter(Boolean).filter(r => !r.both_confirmed)
log('CONFIRMED ' + confirmed.length + '/' + results.length + '; CONCERNS: ' + concerns.map(c=>c.fix_id).join(', '))
return { total: results.length, confirmed_count: confirmed.length, concerns, all: results.filter(Boolean) }
